mapper.select:
SELECT id, skill_id, skill_code, module_key, input_params, output_result,
       tokens_prompt, tokens_completion, duration_ms, status, error_message, created_by, created_at
FROM ai_skill_execution_log

    AND skill_id = #{skillId}
    AND skill_code = #{skillCode}
    AND module_key = #{moduleKey}
    AND status = #{status}
    AND created_by = #{createdBy}

ORDER BY created_at DESC
